import React from "react";
import Topnav from "../components/Topnav";
import Footer from "../components/Footer";
import homeImage_1 from "../assets/home_1.png";
import homeImage_2 from "../assets/home_2.png";
import homeImage_3 from "../assets/home_3.png";
import contentData from "../assets/content.json";

function Landingpage() {
  return (
    <>
      <Topnav />

      {/* Main Section */}
      <section className="bg-gray-50 py-16">
        <h1 className="text-4xl font-extrabold text-center mb-16 text-gray-900">
          How does <span className="text-blue-600">GemAnaIyzer</span> work?
        </h1>

        {/* Section 1 */}
        <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-2 gap-12 items-center px-6 mb-20">
          <div>
            <h2 className="text-2xl font-bold mb-4">
              {contentData.section1.title}
            </h2>
            <p className="text-gray-600 mb-6 leading-relaxed">
              {contentData.section1.description}
            </p>
            <button className="px-6 py-3 rounded-full bg-black text-white font-medium hover:bg-gray-800 transition">
              Learn More
            </button>
          </div>

          <div className="flex justify-center">
            <img
              src={homeImage_1}
              alt="Gem Analyzer"
              className="w-96 h-auto drop-shadow-lg"
            />
          </div>
        </div>

        {/* Section 2 */}
        <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-2 gap-12 items-center px-6 mb-20">
          <div className="flex justify-center md:order-1 order-2">
            <img
              src={homeImage_2}
              alt="Gem Analysis"
              className="w-96 h-auto drop-shadow-lg"
            />
          </div>

          <div className="md:order-2 order-1">
            <h2 className="text-2xl font-bold mb-4">
              {contentData.section2.title}
            </h2>
            <p className="text-gray-600 mb-6 leading-relaxed">
              {contentData.section2.description}
            </p>
            <button className="px-6 py-3 rounded-full bg-blue-600 text-white font-medium hover:bg-blue-700 transition">
              Get Started
            </button>
          </div>
        </div>

        {/* Section 3 */}
        <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-2 gap-12 items-center px-6">
          <div>
            <h2 className="text-2xl font-bold mb-4">
              {contentData.section3.title}
            </h2>
            <p className="text-gray-600 mb-6 leading-relaxed">
              {contentData.section3.description}
            </p>
            <button className="px-6 py-3 rounded-full bg-black text-white font-medium hover:bg-gray-800 transition">
              Learn More
            </button>
          </div>

          <div className="flex justify-center">
            <img
              src={homeImage_3}
              alt="Gem Results"
              className="w-96 h-auto drop-shadow-lg"
            />
          </div>
        </div>
      </section>

      <Footer />
    </>
  );
}

export default Landingpage;
